use std::fmt::{self, Display, Debug};

trait Showable { 
    fn display_info(&self) -> String;
}

trait Validatable<T> { 
    fn is_valid(&self) -> bool;
}

struct Person<T: Display + Debug> {
    name: String,
    age: T,
    identifier: Option<String>
}

impl<T: Display + Debug> Showable for Person<T> {
    fn display_info(&self) -> String {
        format!("Name: {}, Age: {}", self.name, self.age)
    }
}

impl<T: Display + Debug> Validatable<T> for Person<T> where T: std::fmt::Display {
    fn is_valid(&self) -> bool {
        !self.identifier.is_none()
    }
}

fn main() {
    let valid_person = Person {
        name: String::from("Alice"),
        age: 30,
        identifier: Some(String::from("ID123"))
    };

    let invalid_person = Person {
        name: String::from("Bob"),
        age: 25,
        identifier: None
    };

    println!("--- Checking Valid Person ---n{}", valid_person.display_info());
    if valid_person.is_valid() {
        println!("Status: The record is complete and ready to use.");
    } else {
        println!("Status: Missing required information.");
    }

    println!("n--- Checking Invalid Person ---n{}", invalid_person.display_info());
    if invalid_person.is_valid() {
        println!("Status: The record is complete and ready to use.");
    } else {
        println!("Status: Missing required information.");
    }
}

