use std::fmt::{self, Display};
use std::error::Error;
use std::fmt::Debug;
use std::collections::HashMap;


trait PrintableSuper {
    fn print_info(&self) -> String;
}

impl<T: Display + Debug> PrintableSuper for T {
    fn print_info(&self) -> String {
        format!("Object can be displayed and debugged: {}", self)
    }
}

trait DataFormatter {
    fn format_data(&self, data: &HashMap<String, i32>) -> Result<String, Box<dyn Error>>;
}

struct Record { 
    id: u32,
    name: String,
    value: i32
}

impl Display for Record {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Record({})", self.id)
    }
}

impl Debug for Record {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("Record")
            .field("id", &self.id)
            .field("name", &self.name)
            .field("value", &self.value)
            .finish()
    }
}

impl DataFormatter for Record {
    fn format_data(&self, data: &HashMap<String, i32>) -> Result<String, Box<dyn Error>> {
        if let Some(val) = data.get("key") {
            Ok(format!("Formatted output for record {} with value {}", self.id, val))
        } else {
            Err("Required key not found in map".into())
        }
    }
}

fn main() {
    let mut data = HashMap::new();
    data.insert("key".to_string(), 42);

    let record1 = Record { id: 1, name: "Test".to_string(), value: 10 };

    if let Some(super_impl) = (&record1 as &dyn PrintableSuper).print_info().into() {
        println!("Successfully checked super trait display: {}", super_impl);
    }

    match record1.format_data(&data) {
        Ok(output) => println!("Success formatting: {}", output),
        Err(e) => println!("Error formatting: {}", e),
    }
}

use std::fmt::{self, Display, Debug};

trait HasIdentifier {}

impl<T: ?Sized> HasIdentifier for T where T: ToString {}

trait PrintableSuperTrait: Display + Debug + HasIdentifier {}

struct UserData {
    id: String,
    name: String,
}

impl Display for UserData {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "User ID: {}", self.id)
    }
}

impl Debug for UserData {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "User ID: {}, Name: {}", self.id, self.name)
    }
}

impl PrintableSuperTrait for UserData where Self: std::fmt::Debug + Display + HasIdentifier {}

fn main() {
    let user = UserData {
        id: String::from("A123"),
        name: String::from("Alice")
    };
    println!("Successfully printed object: {}", user);
}
